  ensures k == 1 <==> IsGood(s)
{
  var zeros := 0;
  var ones := 0;
  var i := 0;
  while i < |s|
    invariant 0 <= i <= |s|
    invariant zeros == CountChar(s[..i], '0')
    invariant ones == CountChar(s[..i], '1')
  {
    assert zeros + ones == i;
    if s[i] == '0' {
      zeros := zeros + 1;
    } else {
      ones := ones + 1;
    }
    i := i + 1;
  }
  assert zeros == CountChar(s, '0');
  if zeros != ones {
    k := 1;
    parts := [s];
    FlattenSingleton(s);
  } else {
    k := 2;
    var first := s[..|s| - 1];
    var second := [s[|s| - 1]];
    parts := [first, second];

    // Flatten proof
    assert first + second == s;
    FlattenPair(first, second);

    // first is good: odd-length binary string can't have equal counts
    CountCharSum(s);
    CountCharSum(first);
    assert IsGood(first);

    // second is good: single character
    assert IsGood(second);
  }
}
